"use client";

import { zodResolver } from "@hookform/resolvers/zod";
import { Elements } from "@stripe/react-stripe-js";
import { useRef, useState } from "react";
import { useForm } from "react-hook-form";
import { z } from "zod";

import { getStripe } from "@/shared/lib/stripe/get-stripe";
import { Button } from "@/shared/ui/shadcn/button";
import { Dialog, DialogContent, DialogTitle } from "@/shared/ui/shadcn/dialog";
import { Input } from "@/shared/ui/shadcn/input";
import { Label } from "@/shared/ui/shadcn/label";
import { type CardSetupFormRef, CardSetupForm } from "./card-setup-form";

const cardFormSchema = z.object({
  cardholderName: z.string().min(1, "Name on card is required"),
});

type CardFormValues = z.infer<typeof cardFormSchema>;

interface AddPaymentMethodModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export function AddPaymentMethodModal({
  isOpen,
  onClose,
}: AddPaymentMethodModalProps) {
  const cardFormRef = useRef<CardSetupFormRef>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const {
    register,
    watch,
    formState: { errors },
  } = useForm<CardFormValues>({
    resolver: zodResolver(cardFormSchema),
    defaultValues: { cardholderName: "" },
  });

  const cardholderName = watch("cardholderName");

  async function handleAddCard() {
    if (isSubmitting) return;
    setIsSubmitting(true);
    try {
      await cardFormRef.current?.submit();
    } finally {
      setIsSubmitting(false);
    }
  }

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="w-[calc(100vw-2rem)] max-w-[500px] gap-0 rounded-2xl border border-[#D6D3D1] bg-[#F5F3EF] p-0 shadow-[0px_20px_28px_rgba(0,0,0,0.05)]">
        {/* Card logos row */}
        <div className="flex items-start px-6 pt-6 pb-4">
          <div className="flex items-center gap-1.5">
            {/* Visa */}
            <div className="flex h-7 w-11 items-center justify-center rounded border border-[#D6D3D1] bg-white px-1.5">
              <span className="font-bold font-new-sans text-[#1434CB] text-[11px] italic leading-none tracking-tight">
                VISA
              </span>
            </div>
            {/* Mastercard */}
            <div className="flex h-7 w-11 items-center justify-center rounded border border-[#D6D3D1] bg-white">
              <div className="relative flex items-center">
                <div className="h-[18px] w-[18px] rounded-full bg-[#EB001B]" />
                <div className="-ml-2.5 h-[18px] w-[18px] rounded-full bg-[#F79E1B] opacity-90" />
              </div>
            </div>
            {/* Generic */}
            <div className="flex h-7 w-11 items-center justify-center rounded border border-[#D6D3D1] bg-white">
              <span className="font-new-sans text-[#A8A29E] text-sm leading-none">
                ···
              </span>
            </div>
          </div>
        </div>

        {/* Title + subtitle */}
        <div className="px-6 pb-5">
          <DialogTitle className="font-light font-new-serif text-2xl text-[#44403C] leading-[120%]">
            Add debit or credit card
          </DialogTitle>
          <p className="mt-1 font-new-sans text-[#A8A29E] text-sm leading-[150%]">
            Ensure card details are correct.
          </p>
        </div>

        {/* Divider */}
        <div className="border-[#D6D3D1] border-t" />

        {/* Form fields */}
        <div className="flex flex-col gap-4 px-6 py-5">
          {/* Name on Card */}
          <div className="flex flex-col gap-2">
            <Label className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
              Name on Card<span className="text-destructive">*</span>
            </Label>
            <Input
              {...register("cardholderName")}
              placeholder="John Doe"
              className="h-12 rounded-[4px] border border-[#A8A29E] bg-[#F5F3EF] px-3 font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E]"
            />
            {errors.cardholderName && (
              <p className="font-new-sans text-destructive text-xs">
                {errors.cardholderName.message}
              </p>
            )}
          </div>

          {/* Stripe card elements */}
          <Elements stripe={getStripe()}>
            <CardSetupForm
              ref={cardFormRef}
              onClose={onClose}
              cardholderName={cardholderName}
            />
          </Elements>
        </div>

        {/* Footer */}
        <div className="flex gap-3 border-[#D6D3D1] border-t px-6 py-5">
          <button
            type="button"
            onClick={onClose}
            className="flex h-12 flex-1 items-center justify-center rounded-lg border border-[#A8A29E] bg-[#F5F3EF] font-medium font-new-sans text-[#44403C] text-base transition-opacity hover:opacity-70"
          >
            Back
          </button>
          <Button
            type="button"
            onClick={handleAddCard}
            loading={isSubmitting}
            disabled={isSubmitting}
            className="h-12 flex-1 rounded-lg bg-[#021171] font-medium font-new-sans text-[#F5F3EF] text-base"
          >
            Add Card
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

