"use client";

import dynamic from "next/dynamic";
import { useState } from "react";

import { useBuybackAsset } from "@/shared/api/query-hooks/use-buyback";
import { useWalletInfo } from "@/shared/api/query-hooks/use-wallet";
import type { BuybackDetailResponse } from "@/shared/api/services/buyback";
import { centsToDollars } from "@/shared/lib/utils/price-formatter";
import { useCurrencyFormatter } from "@/shared/lib/hooks/use-currency-formatter";
import { AssetHandoverOption } from "@/shared/types/asset.types";
import { Button } from "@/shared/ui/button";
import {
  Dialog,
  DialogCloseButton,
  DialogContent,
  DialogTitle,
} from "@/shared/ui/dialog";
import { toast } from "@/shared/ui/notification";
import { PaymentMethodSelector } from "@/widgets/payment-method-selector";

const DepositFundsModal = dynamic(
  () =>
    import("@/widgets/deposit-funds-modal").then((mod) => ({
      default: mod.DepositFundsModal,
    })),
  { ssr: false },
);

interface BuybackPaymentModalProps {
  isOpen: boolean;
  onClose: () => void;
  buyback: BuybackDetailResponse;
}

export function BuybackPaymentModal({
  isOpen,
  onClose,
  buyback,
}: BuybackPaymentModalProps) {
  const { formatAmount } = useCurrencyFormatter();
  const buybackAsset = useBuybackAsset();
  const { data: walletInfo } = useWalletInfo();
  const [isDepositModalOpen, setIsDepositModalOpen] = useState(false);
  useState(false);

  const outstandingAmountCents =
    buyback.computedDetails?.outstandingAmountCents || 0;

  const currentBalanceCents = walletInfo?.balance || 0;
  const hasSufficientBalance = currentBalanceCents >= outstandingAmountCents;
  const shortfallCents = outstandingAmountCents - currentBalanceCents;

  const handleSubmit = async () => {
    if (!hasSufficientBalance) {
      return;
    }

    try {
      await buybackAsset.mutateAsync({
        buybackId: buyback.id,
        assetHandoverOption: AssetHandoverOption.Courier,
      });

      toast.success("Payment Successful!", {
        description: "Payment has been processed from your wallet",
      });

      onClose();
    } catch (error: unknown) {
      const err = error as {
        response?: {
          data?: {
            error?: string;
            message?: string;
          };
        };
      };

      toast.error("Payment Failed", {
        description:
          err.response?.data?.message ||
          "Unable to process payment. Please try again.",
      });
    }
  };

  const handleSelectTopUp = () => {
    setIsDepositModalOpen(true);
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="w-[514px] gap-[40px] p-[30px]">
        <div className="flex flex-col gap-[20px]">
          <div className="flex items-center justify-between">
            <DialogTitle className="font-medium font-sans text-[#2B3144] text-[23px] leading-[1.217em]">
              Complete Buyback Payment
            </DialogTitle>
            <DialogCloseButton />
          </div>

          <div className="flex flex-col gap-[20px]">
            <h3 className="font-bold font-serif text-base leading-[1.199em]">
              Payment Details
            </h3>

            <div className="flex flex-col gap-[10px]">
              <div className="flex items-center gap-[6px]">
                <span className="font-serif text-sm leading-[1.199em]">
                  Current Balance:
                </span>
                <span className="ml-auto font-bold font-serif text-sm leading-[1.199em]">
                  {formatAmount(currentBalanceCents)}
                </span>
              </div>

              <div className="flex items-center gap-[6px]">
                <span className="font-bold font-serif text-sm leading-[1.199em]">
                  Amount to Pay:
                </span>
                <span className="ml-auto font-bold font-serif text-lg leading-[1.199em]">
                  {formatAmount(outstandingAmountCents)}
                </span>
              </div>

              {!hasSufficientBalance && (
                <div className="mt-2 rounded-[10px] border border-destructive/20 bg-destructive/5 p-3">
                  <p className="font-bold font-sans text-destructive text-sm">
                    Insufficient Balance
                  </p>
                  <p className="font-sans text-destructive/80 text-xs leading-[1.4em]">
                    You need {formatAmount(shortfallCents)} more in your
                    wallet to complete this payment.
                  </p>
                </div>
              )}

              {hasSufficientBalance && (
                <p className="font-sans text-[#6C7080] text-xs leading-[1.4em]">
                  This amount will be deducted from your wallet balance. After
                  payment, you can arrange the asset return separately.
                </p>
              )}
            </div>
          </div>

          {hasSufficientBalance ? (
            <Button
              type="button"
              onClick={handleSubmit}
              loading={buybackAsset.isPending}
              disabled={buybackAsset.isPending}
              className="h-[60px] w-full rounded-[10px] font-medium font-sans text-lg"
            >
              Pay Now
            </Button>
          ) : (
            <PaymentMethodSelector
              isOpen={true}
              amount={outstandingAmountCents}
              currentBalance={currentBalanceCents}
              shortfall={shortfallCents}
              onSelectTopUp={handleSelectTopUp}
            />
          )}
        </div>
      </DialogContent>

      <DepositFundsModal
        isOpen={isDepositModalOpen}
        onClose={() => setIsDepositModalOpen(false)}
        suggestedAmount={centsToDollars(shortfallCents)}
      />
    </Dialog>
  );
}

