import { getApi } from "@/shared/api/api";
import { API_ROUTES } from "@/shared/config/api-routes";
import type {
  CreateNowPaymentsCheckoutRequest,
  NowPaymentsCheckoutResponse,
} from "@/shared/types/payment.types";

export interface NowPaymentsCurrenciesResponse {
  currencies: string[];
}

export const nowpaymentsCheckoutService = {
  async createCheckout(
    request: CreateNowPaymentsCheckoutRequest,
  ): Promise<NowPaymentsCheckoutResponse> {
    const api = await getApi();
    const { data } = await api.post<NowPaymentsCheckoutResponse>(
      API_ROUTES.NOWPAYMENTS_CHECKOUT,
      request,
    );
    return data;
  },

  async getCurrencies(): Promise<NowPaymentsCurrenciesResponse> {
    const api = await getApi();
    const { data } = await api.get<NowPaymentsCurrenciesResponse>(
      API_ROUTES.NOWPAYMENTS_CURRENCIES,
    );
    return data;
  },
};

